        <p style={{ marginBottom: '20px' }}>Your order has been confirmed and is being processed.</p>
        <p style={{ marginBottom: '30px', fontSize: '0.9em', color: '#666' }}>
          Transaction Reference: {paymentSuccess.tx_ref}
        </p>
        <div style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
          <button
            onClick={generateInvoice}
            style={{
              background: '#2196F3',
              color: 'white',
              border: 'none',
              padding: '10px 20px',
              borderRadius: '5px',
              cursor: 'pointer'
            }}
          >
            📄 Download Invoice
          </button>
          <button
            onClick={onClose}
            style={{
              background: '#4CAF50',
              color: 'white',
              border: 'none',
              padding: '10px 20px',
              borderRadius: '5px',
              cursor: 'pointer'
            }}
          >
            Continue Shopping
          </button>
        </div>
      </div>
    </div>
  );
};

const getCategoryIcon = (categoryName) => {
  const icons = {
    'Electronics': 'laptop',
    'Clothing': 'tshirt',
    'Home': 'home'
  };
  return icons[categoryName] || 'box';
};

export default App;
